section.code:
{
  "$schema": "http://json-schema.org/draft-07/schema#",
  "$id": "https://faion.net/schemas/accessibility.json",
  "title": "Accessibility",
  "type": "object",
  "required": [
    "artefact_id",
    "conformance_target",
    "tooling_baseline",
    "ci_gates",
    "responsibilities",
    "third_party_policy",
    "regression_test_policy",
    "owner",
    "last_touched",
    "template_version",
    "status"
  ],
  "properties": {
    "artefact_id": {
      "type": "string",
      "description": "slug + ISO date or UUID",
      "minLength": 1
    },
    "owner": {
      "type": "string",
      "description": "single named owner; generic group terms forbidden",
      "minLength": 1
    },
    "last_touched": {
      "type": "string",
      "description": "ISO-8601 timestamp",
      "format": "date-time"
    },
    "template_version": {
      "type": "string",
      "description": "semver matching methodology frontmatter at write time"
    },
    "status": {
      "type": "string",
      "description": "draft|ready_for_review|approved|archived",
      "minLength": 1
    },
    "conformance_target": {
      "type": "string",
      "description": "WCAG-2.1-A | WCAG-2.1-AA | WCAG-2.1-AAA | section-508"
    },
    "tooling_baseline": {
      "type": "array",
      "minItems": 1
    },
    "ci_gates": {
      "type": "array",
      "minItems": 1,
      "description": "{routes, severity_floor, command}"
    },
    "responsibilities": {
      "type": "object",
      "description": "role \u2192 wcag-category list"
    },
    "third_party_policy": {
      "type": "string",
      "minLength": 1
    },
    "regression_test_policy": {
      "type": "string",
      "minLength": 1
    }
  },
  "additionalProperties": false
}
